const brief = $input.first().json;
const mechanics = ['question_box', 'poll', 'short_video', 'social_proof', 'dm_keyword', 'reply_prompt', 'countdown'];
const week = [];
for (let day = 1; day <= 7; day++) {
  week.push({
    day,
    stories: [
      {
        story_type: 'connection',
        hook: `Day ${day}: name the audience problem in plain language`,
        visual: 'simple talking-head or behind-the-scenes clip',
        copy_angle: `Connect ${brief.offer_name} to a real weekly pain point`,
        cta: 'Use a low-pressure reply prompt',
        interaction_mechanic: mechanics[(day - 1) % mechanics.length],
        production_note: 'Record or assemble in under 10 minutes'
      },
      {
        story_type: 'soft_sale',
        hook: `Day ${day}: invite one small next step`,
        visual: 'offer screenshot, proof snippet, or simple text slide',
        copy_angle: `Position ${brief.offer_name} as the next practical step`,
        cta: brief.primary_cta,
        interaction_mechanic: 'dm_keyword',
        production_note: 'Reuse the connection story context'
      }
    ]
  });
}
return [{ json: { module_id: 'story-sales-engine', generated_at: new Date().toISOString(), brief, week } }];
